-- Phone OTP Audit Logs migration\nCREATE TABLE IF NOT EXISTS public.phone_otp_audit_logs (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  phone text NOT NULL,\n  event text NOT NULL, -- requested, verified, failed, expired, rate_limit\n  created_at timestamptz NOT NULL DEFAULT now()\n);\n\n-- Enable Row Level Security for audit logs\nALTER TABLE public.phone_otp_audit_logs ENABLE ROW LEVEL SECURITY;\n\n-- Deny direct client access\nDROP POLICY IF EXISTS phone_otp_audit_logs_deny_all ON public.phone_otp_audit_logs;\nCREATE POLICY phone_otp_audit_logs_deny_all ON public.phone_otp_audit_logs FOR ALL USING (false);\n
